import{_ as a,o as i,c as t,a2 as r}from"./chunks/framework.LN3EJxkW.js";const u=JSON.parse('{"title":"Network 瀑布图：关键请求链、优先级与端到端定位","description":"","frontmatter":{"stage":"intermediate"},"headers":[],"relativePath":"01-frontend/notes/browser-runtime/06-network-waterfall.md","filePath":"01-frontend/notes/browser-runtime/06-network-waterfall.md","lastUpdated":1784371427000}'),n={name:"01-frontend/notes/browser-runtime/06-network-waterfall.md"};function s(l,e,o,h,p,d){return i(),t("div",null,[...e[0]||(e[0]=[r(`<h1 id="network-瀑布图-关键请求链、优先级与端到端定位" tabindex="-1">Network 瀑布图：关键请求链、优先级与端到端定位 <a class="header-anchor" href="#network-瀑布图-关键请求链、优先级与端到端定位" aria-label="Permalink to &quot;Network 瀑布图：关键请求链、优先级与端到端定位&quot;">​</a></h1><p>瀑布图按时间展示请求排队、连接、发送、等待和接收，但颜色条不是根因。中级分析需要把请求 initiator、dependency、priority、cache、protocol 与服务器 trace 连接起来，区分网络慢、发现晚、服务端慢、主线程阻塞和资源竞争。</p><h2 id="_1-先定义分析问题" tabindex="-1">1. 先定义分析问题 <a class="header-anchor" href="#_1-先定义分析问题" aria-label="Permalink to &quot;1. 先定义分析问题&quot;">​</a></h2><p>同一瀑布可回答不同问题：</p><ul><li>为什么 LCP 图片开始晚；</li><li>为什么 API TTFB 高；</li><li>为什么路由 chunk 404；</li><li>为什么相同 URL 请求两次；</li><li>为什么资源下载完成但页面仍空白；</li><li>为什么第三方拖慢交互。</li></ul><p>先选择用户动作、指标和样本，再录制。没有问题定义的瀑布容易只做请求数量清单。</p><h2 id="_2-请求阶段" tabindex="-1">2. 请求阶段 <a class="header-anchor" href="#_2-请求阶段" aria-label="Permalink to &quot;2. 请求阶段&quot;">​</a></h2><div class="language-mermaid vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A[&quot;Queueing/Stalled&quot;] --&gt; B[&quot;DNS&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt; C[&quot;Connect&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt; D[&quot;TLS&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D --&gt; E[&quot;Request sent&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    E --&gt; F[&quot;Waiting / TTFB&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    F --&gt; G[&quot;Content download&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    G --&gt; H[&quot;Decode/Parse/Execute&quot;]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><p>最后一段常不在 Network timing 条内，需要 Performance 面板。</p><h3 id="_2-1-queueing-stalled" tabindex="-1">2.1 Queueing / Stalled <a class="header-anchor" href="#_2-1-queueing-stalled" aria-label="Permalink to &quot;2.1 Queueing / Stalled&quot;">​</a></h3><p>可能来自请求优先级、连接可用性、代理协商、磁盘 cache、Service Worker、浏览器调度或主线程发起延迟。HTTP/2/3 有多路复用仍受服务器并发、拥塞和浏览器优先级限制。</p><h3 id="_2-2-dns、connect、ssl" tabindex="-1">2.2 DNS、Connect、SSL <a class="header-anchor" href="#_2-2-dns、connect、ssl" aria-label="Permalink to &quot;2.2 DNS、Connect、SSL&quot;">​</a></h3><p>仅新连接出现明显时间；复用连接时通常为 0。跨源详细 Resource Timing 没有 <code>Timing-Allow-Origin</code> 时字段可被清零。</p><h3 id="_2-3-request-sent" tabindex="-1">2.3 Request Sent <a class="header-anchor" href="#_2-3-request-sent" aria-label="Permalink to &quot;2.3 Request Sent&quot;">​</a></h3><p>GET 通常很短；大上传、慢上行或 request streaming 会明显。DevTools 显示的 header 体积和实际协议压缩不同；Cookie 过大仍会在许多请求携带并增加处理。</p><h3 id="_2-4-waiting-ttfb" tabindex="-1">2.4 Waiting / TTFB <a class="header-anchor" href="#_2-4-waiting-ttfb" aria-label="Permalink to &quot;2.4 Waiting / TTFB&quot;">​</a></h3><p>从请求发送到首字节，包括去程网络、边缘/CDN、服务端排队/处理、回源和回程首字节。不能直接叫“服务器计算”。用 Server-Timing、trace 和边缘日志分解。</p><h3 id="_2-5-content-download" tabindex="-1">2.5 Content Download <a class="header-anchor" href="#_2-5-content-download" aria-label="Permalink to &quot;2.5 Content Download&quot;">​</a></h3><p>受编码后大小、带宽、丢包、拥塞、流式速度和竞争影响。下载条很长但 transfer size 小，可能是服务器流式/限速，而不只是用户带宽。</p><h2 id="_3-initiator-与依赖图" tabindex="-1">3. Initiator 与依赖图 <a class="header-anchor" href="#_3-initiator-与依赖图" aria-label="Permalink to &quot;3. Initiator 与依赖图&quot;">​</a></h2><p>Initiator 说明请求由 parser、CSS、script、preload、redirect、fetch 或其他资源触发。关键链不是最长条集合，而是“前一个完成/执行后才发现或允许下一个开始”的依赖。</p><div class="language-mermaid vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A[&quot;document&quot;] --&gt; B[&quot;app.css&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt; C[&quot;hero.jpg&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A --&gt; D[&quot;app.js&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D --&gt; E[&quot;dynamic route.js&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    E --&gt; F[&quot;API /courses&quot;]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>减少 C 大小不能消除 A→B→C 的发现延迟；将 hero 放 HTML 可缩短链。API 若必须等 route JS 执行，可由路由 loader/SSR 提前。</p><h2 id="_4-priority" tabindex="-1">4. Priority <a class="header-anchor" href="#_4-priority" aria-label="Permalink to &quot;4. Priority&quot;">​</a></h2><p>浏览器按资源类型、发现位置、可见性、fetchpriority 和内部策略调度。Priority 是相对且可动态变化，不是严格队列。</p><p>典型问题：</p><ul><li>LCP img 加 loading=lazy，优先级和时机太晚；</li><li>所有 preload/fetchpriority high 抢关键 CSS；</li><li>第三方大脚本早请求；</li><li>字体全预载；</li><li>iframe/图片未 lazy，首屏带宽竞争。</li></ul><p>修改后验证 start time、实际带宽和 LCP，不只看 Priority 文字。</p><h2 id="_5-cache-与传输字段" tabindex="-1">5. Cache 与传输字段 <a class="header-anchor" href="#_5-cache-与传输字段" aria-label="Permalink to &quot;5. Cache 与传输字段&quot;">​</a></h2><p>DevTools 常见：</p><ul><li><code>(memory cache)</code>：当前浏览器进程内存复用；</li><li><code>(disk cache)</code>：持久 HTTP cache；</li><li><code>304</code>：网络重验证后复用 body；</li><li><code>from ServiceWorker</code>：响应经 worker；可能内部又访问网络/cache；</li><li>transfer size 与 resource size：压缩/协议头/cache 影响差异。</li></ul><p>禁用 cache 是冷启动实验，不代表真实重复访问。报告同时给 cold、warm、navigation type 和 Service Worker 状态。</p><h2 id="_6-protocol、connection-id-与多路复用" tabindex="-1">6. Protocol、Connection ID 与多路复用 <a class="header-anchor" href="#_6-protocol、connection-id-与多路复用" aria-label="Permalink to &quot;6. Protocol、Connection ID 与多路复用&quot;">​</a></h2><p>显示 Protocol、Connection ID、Remote Address：</p><ul><li>同一 origin 的 h2 请求通常复用连接；</li><li>多个连接可能因 credentials、代理、服务器设置或不同 origin；</li><li>h3 回退到 h2 需按样本记录；</li><li>connection coalescing 可让证书/DNS 条件满足的不同 origin 共用，但不能依赖为应用契约。</li></ul><p>大量短请求在 h2/h3 不等于免费，仍有 header、服务端工作、优先级和 JS 处理成本。</p><h2 id="_7-重定向链" tabindex="-1">7. 重定向链 <a class="header-anchor" href="#_7-重定向链" aria-label="Permalink to &quot;7. 重定向链&quot;">​</a></h2><p>DevTools 勾选 Preserve log。检查：</p><ul><li>http→https；</li><li>裸域→www；</li><li>locale/auth；</li><li>API 版本；</li><li>trailing slash；</li><li>登录循环。</li></ul><p>主导航跨源重定向可能重复连接。服务端直接产生 canonical URL；内部链接一开始就指最终地址。写请求 307/308 保留方法，301/302/303 行为需按客户端和规范测试。</p><h3 id="_7-1-waterfall-之外的关键列" tabindex="-1">7.1 Waterfall 之外的关键列 <a class="header-anchor" href="#_7-1-waterfall-之外的关键列" aria-label="Permalink to &quot;7.1 Waterfall 之外的关键列&quot;">​</a></h3><p>瀑布条必须和其他字段一起读：</p><table tabindex="0"><thead><tr><th>字段</th><th>能回答</th><th>不能直接推出</th></tr></thead><tbody><tr><td>Status</td><td>HTTP 结果或 cache 验证</td><td>200 不代表业务数据正确</td></tr><tr><td>Type</td><td>document/script/fetch/font 等</td><td>initiator 的完整调用链</td></tr><tr><td>Initiator</td><td>parser、脚本调用栈、依赖</td><td>服务端内部依赖</td></tr><tr><td>Priority</td><td>浏览器当前调度提示</td><td>一定先完成或固定带宽</td></tr><tr><td>Size</td><td>transfer/resource/cache 信息</td><td>JS 解析执行成本</td></tr><tr><td>Time</td><td>从排队到完成</td><td>用户何时看到或可交互</td></tr><tr><td>Protocol</td><td>h2/h3/http1.1</td><td>CDN 到源站协议</td></tr><tr><td>Remote Address</td><td>当前网络端点</td><td>最终源站物理位置</td></tr><tr><td>Connection ID</td><td>是否可能复用连接</td><td>内部 stream 队列全部细节</td></tr></tbody></table><p>自定义 Response Headers 列可显示 <code>x-cache</code>、<code>server-timing</code>、release 和 request ID。只展示安全字段；不要让内部拓扑和用户标识进入公共响应。</p><h3 id="_7-2-request-response-体" tabindex="-1">7.2 Request/Response 体 <a class="header-anchor" href="#_7-2-request-response-体" aria-label="Permalink to &quot;7.2 Request/Response 体&quot;">​</a></h3><p>API 慢时检查请求是否意外上传巨大 JSON、base64 文件或全量查询；响应是否返回 50,000 条而 UI 只显示 50 条。Preview 自动格式化不等于传输格式，结合 Content-Encoding、Content-Length、transfer size 和 Response 原文。</p><p>OPTIONS 可能是 CORS preflight，不是重复业务调用。能否减少预检取决于跨源、方法和请求头设计；不能为少一个请求绕过 CSRF、授权或内容类型安全。敏感 payload 不进入共享 HAR、截图和录屏。</p><h3 id="_7-3-按资源类型定位后续阶段" tabindex="-1">7.3 按资源类型定位后续阶段 <a class="header-anchor" href="#_7-3-按资源类型定位后续阶段" aria-label="Permalink to &quot;7.3 按资源类型定位后续阶段&quot;">​</a></h3><p>Document 检查 redirect、TTFB、streaming 和 HTML 首批资源发现。CSS 检查 @import、阻塞、字体/图片依赖，下载后转 Performance 查看样式计算。JavaScript 检查 chunk/modulepreload，下载后查看 parse/compile/evaluate。</p><p>图片检查 srcset 候选、priority、尺寸、decode；字体检查 preload CORS、子集和文本命中。Fetch/XHR 检查 Effect 重复、abort、retry、credentials、cache 与 schema。WebSocket/SSE 长期 pending 正常，改看握手、消息帧、心跳、重连和 backpressure。</p><h3 id="_7-4-屏幕截图与-filmstrip" tabindex="-1">7.4 屏幕截图与 filmstrip <a class="header-anchor" href="#_7-4-屏幕截图与-filmstrip" aria-label="Permalink to &quot;7.4 屏幕截图与 filmstrip&quot;">​</a></h3><p>Performance filmstrip 把请求完成与视觉变化对齐。若 CSS 在 600 ms 完成但首屏到 2 s 才出现，查看主线程、字体和图片 decode；若 LCP 资源 1 s 完成但 3 s 才绘制，Network 不是终点。</p><p>截图只用于定位视觉时序，核心结论仍记录请求时间、主线程事件和 Web Vitals。动画、cookie banner 和随机内容会污染对比，应固定输入和 viewport。</p><h2 id="_8-案例一-lcp-4-2-秒但下载不慢" tabindex="-1">8. 案例一：LCP 4.2 秒但下载不慢 <a class="header-anchor" href="#_8-案例一-lcp-4-2-秒但下载不慢" aria-label="Permalink to &quot;8. 案例一：LCP 4.2 秒但下载不慢&quot;">​</a></h2><h3 id="输入" tabindex="-1">输入 <a class="header-anchor" href="#输入" aria-label="Permalink to &quot;输入&quot;">​</a></h3><p>hero.jpg 传输 180 ms，开始于 2.5 s；Initiator 是 <code>marketing.css</code>，该 CSS 由 <code>route.js</code> 动态 import 后插入。LCP 4.2 s。</p><h3 id="推理" tabindex="-1">推理 <a class="header-anchor" href="#推理" aria-label="Permalink to &quot;推理&quot;">​</a></h3><ol><li>图片大小不是主瓶颈；</li><li>请求链 document→main.js→route.js→CSS→hero；</li><li>hero 是内容图，应在 SSR/HTML 出现；</li><li>route CSS 可在路由匹配时预加载，但仍不如 HTML 直接发现；</li><li>设置尺寸和高优先级。</li></ol><h3 id="输出" tabindex="-1">输出 <a class="header-anchor" href="#输出" aria-label="Permalink to &quot;输出&quot;">​</a></h3><p>hero start 350 ms，LCP p75 2.1 s。验证不同 viewport、DPR、缓存和无 JS HTML。失败分支：预载固定 desktop 图造成 mobile 双下载，改响应式 preload 或只依赖 picture。</p><h2 id="_9-案例二-api-ttfb-p95-高" tabindex="-1">9. 案例二：API TTFB p95 高 <a class="header-anchor" href="#_9-案例二-api-ttfb-p95-高" aria-label="Permalink to &quot;9. 案例二：API TTFB p95 高&quot;">​</a></h2><h3 id="输入-1" tabindex="-1">输入 <a class="header-anchor" href="#输入-1" aria-label="Permalink to &quot;输入&quot;">​</a></h3><p>Network waiting 2.4 s，DNS/connect 为 0（连接复用）；Server-Timing <code>edge;dur=5, origin;dur=2100, db;dur=1800</code>。服务器 trace 显示缺索引查询。</p><h3 id="处理" tabindex="-1">处理 <a class="header-anchor" href="#处理" aria-label="Permalink to &quot;处理&quot;">​</a></h3><p>前端 preconnect、HTTP/3 和压缩都不能解决主要 1.8 s DB。后端加复合索引/改查询，edge cache 只在响应公共且可陈旧时使用。前端保留 timeout、cancel、retry 边界。</p><h3 id="验证" tabindex="-1">验证 <a class="header-anchor" href="#验证" aria-label="Permalink to &quot;验证&quot;">​</a></h3><p>DB span、origin TTFB 和浏览器 p95 同时下降；结果量和业务正确。失败分支：前端自动重试三次使数据库压力翻倍，重试仅对安全幂等且带 jitter/上限，429/Retry-After 尊重服务策略。</p><h2 id="_10-案例三-请求重复" tabindex="-1">10. 案例三：请求重复 <a class="header-anchor" href="#_10-案例三-请求重复" aria-label="Permalink to &quot;10. 案例三：请求重复&quot;">​</a></h2><h3 id="输入-2" tabindex="-1">输入 <a class="header-anchor" href="#输入-2" aria-label="Permalink to &quot;输入&quot;">​</a></h3><p>同一 font URL 两条 200，一条 Initiator preload，一条 CSS。查看 Request Headers：preload 没 <code>crossorigin</code>，真实字体是 CORS anonymous。</p><h3 id="修复" tabindex="-1">修复 <a class="header-anchor" href="#修复" aria-label="Permalink to &quot;修复&quot;">​</a></h3><p>匹配 crossorigin、URL、type 和 destination。验证 transfer 只有一次。其他重复原因：不同 query/hash（hash 不发服务器但 cache key API不同）、Vary、credentials、Service Worker cache key、redirect、开发 StrictMode effect、无请求去重。</p><p>不能只根据 URL 相同就认定浏览器 bug。</p><h2 id="_11-案例四-下载完成后页面仍空白" tabindex="-1">11. 案例四：下载完成后页面仍空白 <a class="header-anchor" href="#_11-案例四-下载完成后页面仍空白" aria-label="Permalink to &quot;11. 案例四：下载完成后页面仍空白&quot;">​</a></h2><h3 id="输入-3" tabindex="-1">输入 <a class="header-anchor" href="#输入-3" aria-label="Permalink to &quot;输入&quot;">​</a></h3><p>HTML/CSS/JS 在 800 ms 全部完成，FCP 2.8 s。Network 看似正常；Performance 显示 main.js Evaluate 1.3 s、同步 JSON parse 400 ms、style/layout 250 ms。</p><h3 id="处理-1" tabindex="-1">处理 <a class="header-anchor" href="#处理-1" aria-label="Permalink to &quot;处理&quot;">​</a></h3><p>问题是主线程。减少初始 JS、分片数据、移 Worker/服务端、避免渲染巨树。Network 瀑布只证明获取完成，必须切换 Performance。</p><p>验证 CPU slowdown 下 FCP/Long Task/INP；失败注入低端设备。不能通过 preload 更多 JS 改善执行瓶颈。</p><h2 id="_12-har-的用途和风险" tabindex="-1">12. HAR 的用途和风险 <a class="header-anchor" href="#_12-har-的用途和风险" aria-label="Permalink to &quot;12. HAR 的用途和风险&quot;">​</a></h2><p>HAR 可保存请求、响应头、timing 和部分内容，用于离线共享/比较。它可能包含 Cookie、Authorization、query、响应个人数据和内部地址。</p><p>导出前使用无敏感测试账户，清理内容并按安全渠道传输。HAR timing 来自记录浏览器，不等同 packet capture，也不包含完整主线程执行。</p><h2 id="_13-server-timing-与-trace" tabindex="-1">13. Server-Timing 与 Trace <a class="header-anchor" href="#_13-server-timing-与-trace" aria-label="Permalink to &quot;13. Server-Timing 与 Trace&quot;">​</a></h2><p>服务器可响应：</p><div class="language-http vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">http</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">Server-Timing</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> edge;dur=8, app;dur=42, db;dur=17</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>浏览器将其显示在 timing。公共响应不要暴露表名、内部主机或精确安全策略。Duration 是服务器报告，需定义包含范围。</p><p>请求 ID/traceparent 关联 CDN、网关、应用和 DB。浏览器 TTFB - server duration 的差额仍包含网络、队列和未报告阶段。</p><h2 id="_14-rum-与实验室差异" tabindex="-1">14. RUM 与实验室差异 <a class="header-anchor" href="#_14-rum-与实验室差异" aria-label="Permalink to &quot;14. RUM 与实验室差异&quot;">​</a></h2><p>DevTools 单样本用于机制定位；RUM 说明真实分布。切分：</p><ul><li>device memory/CPU proxy；</li><li>effective connection、RTT；</li><li>country/ASN/CDN POP；</li><li>protocol；</li><li>cache/Service Worker；</li><li>release、route、登录状态；</li><li>cold/warm navigation。</li></ul><p>URL 去除 query/ID，低采样保护隐私和成本。p75/p95 不用平均值掩盖长尾。</p><h2 id="_15-诊断决策树" tabindex="-1">15. 诊断决策树 <a class="header-anchor" href="#_15-诊断决策树" aria-label="Permalink to &quot;15. 诊断决策树&quot;">​</a></h2><div class="language-mermaid vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart TD</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A[&quot;用户指标慢&quot;] --&gt; B{&quot;请求开始晚?&quot;}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt;|&quot;是&quot;| C[&quot;查 Initiator/关键链/优先级&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt;|&quot;否&quot;| D{&quot;TTFB 长?&quot;}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D --&gt;|&quot;是&quot;| E[&quot;查连接、edge、origin、trace&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D --&gt;|&quot;否&quot;| F{&quot;download 长?&quot;}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    F --&gt;|&quot;是&quot;| G[&quot;大小/带宽/竞争/流式&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    F --&gt;|&quot;否&quot;| H[&quot;转 Performance: JS/Style/Layout/Paint&quot;]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><h2 id="_16-常见误判" tabindex="-1">16. 常见误判 <a class="header-anchor" href="#_16-常见误判" aria-label="Permalink to &quot;16. 常见误判&quot;">​</a></h2><ol><li>TTFB 全算后端；</li><li>connection time 0 认为没有 TLS；</li><li>disable cache 结果代表所有用户；</li><li>只减请求数，不看关键链和协议；</li><li>async 脚本不阻塞 parser就认为无成本；</li><li>200/304 都当完整下载；</li><li>request priority 当强制保证；</li><li>瀑布结束等于页面可交互。</li></ol><h2 id="_17-生产优化报告" tabindex="-1">17. 生产优化报告 <a class="header-anchor" href="#_17-生产优化报告" aria-label="Permalink to &quot;17. 生产优化报告&quot;">​</a></h2><p>每项结论包含：</p><ul><li>用户问题与指标；</li><li>样本条件和分位数；</li><li>瀑布/trace 证据；</li><li>因果假设；</li><li>A/B 或前后对照；</li><li>收益、成本、回归；</li><li>失败注入；</li><li>发布监控与回滚。</li></ul><h2 id="_18-综合练习" tabindex="-1">18. 综合练习 <a class="header-anchor" href="#_18-综合练习" aria-label="Permalink to &quot;18. 综合练习&quot;">​</a></h2><p>为一个 SSR 列表 + 客户端报表路由录制并优化瀑布。</p><p>验收标准：</p><ol><li>冷/热缓存、h2/h3、快/慢网各 30 样本；</li><li>标出至少两条关键请求链；</li><li>关联 Server-Timing 与 trace；</li><li>制造并定位发现晚、DB 慢、重复 preload、chunk 404；</li><li>Network 与 Performance 分别找一个瓶颈；</li><li>报告 p50/p75/p95 和传输/执行；</li><li>HAR 无敏感信息；</li><li>至少两个优化有成本与回滚标准。</li></ol><h2 id="来源" tabindex="-1">来源 <a class="header-anchor" href="#来源" aria-label="Permalink to &quot;来源&quot;">​</a></h2><ul><li><a href="https://www.w3.org/TR/resource-timing-3/" target="_blank" rel="noreferrer">W3C Resource Timing Level 3</a>（访问日期：2026-07-17）</li><li><a href="https://www.w3.org/TR/navigation-timing-2/" target="_blank" rel="noreferrer">W3C Navigation Timing Level 2</a>（访问日期：2026-07-17）</li><li><a href="https://www.w3.org/TR/server-timing/" target="_blank" rel="noreferrer">W3C Server Timing</a>（访问日期：2026-07-17）</li><li><a href="https://developer.chrome.com/docs/devtools/network/reference/" target="_blank" rel="noreferrer">Chrome DevTools：Network reference</a>（访问日期：2026-07-17）</li><li><a href="https://www.w3.org/TR/trace-context/" target="_blank" rel="noreferrer">OpenTelemetry：Trace Context</a>（访问日期：2026-07-17）</li></ul>`,104)])])}const m=a(n,[["render",s]]);export{u as __pageData,m as default};
